import { useState } from "react";
import CommentItem from "./Comments/CommentItem";
import "./styles/Threads.css";

/* ------------------------------
   Build comment tree (flat → nested)
------------------------------ */
function buildCommentTree(comments) {
    const map = new Map();
    const roots = [];

    comments.forEach(c => {
        map.set(c.id, { ...c, replies: [] });
    });

    map.forEach(c => {
        if (c.parentId) {
            const parent = map.get(c.parentId);
            if (parent) {
                parent.replies.push(c);
            }
        } else {
            roots.push(c);
        }
    });

    return roots;
}

/* ------------------------------
   Comment Section
------------------------------ */
export default function CommentSection({
                                           comments,
                                           user,
                                           newComment,
                                           setNewComment,
                                           onSubmit,
                                           onDelete,
                                           refreshComments
                                       }) {
    const role = String(user?.role || "").toUpperCase();
    const isAdmin = role === "ADMIN";

    const [replyTo, setReplyTo] = useState(null);

    const list = Array.isArray(comments) ? comments : [];
    const tree = buildCommentTree(list);

    /* ------------------------------
       Toggle reactions (LIKE / DISLIKE)
    ------------------------------ */
    async function toggleReaction(comment, type) {
        if (!user) return;

        const hasReacted = comment.reactions?.myReaction === type;
        const url = `http://localhost:8080/api/comments/${comment.id}/reactions?username=${encodeURIComponent(
            user.username
        )}`;

        try {
            if (hasReacted) {
                await fetch(url, { method: "DELETE" });
            } else {
                await fetch(url, {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({ reactionType: type })
                });
            }

            refreshComments?.();
        } catch (err) {
            console.error("Failed to toggle reaction", err);
        }
    }

    /* ------------------------------
       Submit comment / reply
    ------------------------------ */
    const handleSubmit = (e) => {
        e.preventDefault();
        if (!newComment.trim()) return;

        onSubmit(newComment, replyTo);
        setReplyTo(null);
    };


    return (
        <div className="comments-card">
            <h3>Comments</h3>

            {tree.length === 0 && <p>No comments yet.</p>}

            <ul className="comment-list">
                {tree.map(c => (
                    <CommentItem
                        key={c.id}
                        comment={c}
                        user={user}
                        isAdmin={isAdmin}
                        onDelete={onDelete}
                        toggleReaction={toggleReaction}
                        onReply={setReplyTo}
                    />
                ))}
            </ul>

            {/* Reply indicator */}
            {user && replyTo && (
                <div className="replying-indicator">
                    Replying to comment #{replyTo}
                    <button
                        className="cancel-reply-btn"
                        onClick={() => setReplyTo(null)}
                    >
                        Cancel
                    </button>
                </div>
            )}

            {/* Comment / Reply form */}
            <form onSubmit={handleSubmit} className="comment-form">
                <textarea
                    className="textarea"
                    value={newComment}
                    onChange={e => setNewComment(e.target.value)}
                    disabled={!user}
                    placeholder={
                        user
                            ? replyTo
                                ? "Write a reply…"
                                : "Write a comment…"
                            : "Log in to comment"
                    }
                />

                <button
                    className="submit-btn"
                    type="submit"
                    disabled={!user || !newComment.trim()}
                >
                    {replyTo ? "Post Reply" : "Post Comment"}
                </button>
            </form>
        </div>
    );
}
